// ConvertWithVisitor converts HTML to Markdown, invoking visitor callbacks during
// the conversion pipeline.  Pass nil for options to use defaults.
// Pass a struct embedding BaseVisitor and overriding only the methods you need.
func ConvertWithVisitor(html string, options *ConversionOptions, visitor Visitor) (*ConversionResult, error) {
	cHTML := C.CString(html)
	defer C.free(unsafe.Pointer(cHTML))

	var cOptions *C.HTMConversionOptions
	if options != nil {
		jsonBytes, err := json.Marshal(options)
		if err != nil {
			return nil, fmt.Errorf("failed to marshal conversion options: %w", err)
		}
		tmpStr := C.CString(string(jsonBytes))
		cOptions = C.htm_conversion_options_from_json(tmpStr)
		C.free(unsafe.Pointer(tmpStr))
		defer C.htm_conversion_options_free(cOptions)
	}
	if cOptions == nil {
		// Allocate a default options struct so we can attach the visitor.
		defaultJSON := C.CString("{}")
		cOptions = C.htm_conversion_options_from_json(defaultJSON)
		C.free(unsafe.Pointer(defaultJSON))
		defer C.htm_conversion_options_free(cOptions)
	}

	// Register visitor and build the C VTable via the static C helper.
	id := registerVisitor(visitor)
	defer unregisterVisitor(id)
	vtbl := C.makeVisitorVTable()

	// Create a bridge that holds the VTable and the visitor ID as user_data.
	bridge := C.htm_htm_html_visitor_bridge_new(&vtbl, unsafe.Pointer(id))
	if bridge == nil {
		return nil, fmt.Errorf("failed to create visitor bridge")
	}
	defer C.htm_htm_html_visitor_bridge_free(bridge)

	// Attach the bridge to the options struct so convert() picks it up.
	C.htm_options_set_visitor(cOptions, (*C.HTMHtmHtmlVisitorBridge)(bridge))

	ptr := C.htm_convert(cHTML, cOptions)
	if ptr == nil {
		if err := lastError(); err != nil {
			return nil, err
		}
		return nil, fmt.Errorf("conversion returned nil")
	}
	defer C.htm_conversion_result_free(ptr)

	jsonStr := C.GoString((*C.char)(unsafe.Pointer(ptr)))
	var result ConversionResult
	if err := json.Unmarshal([]byte(jsonStr), &result); err != nil {
		return nil, fmt.Errorf("failed to decode conversion result: %w", err)
	}
	return &result, nil
}
